import{_ as a,o as t,c as p,j as r,a as n,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"2.内脏暴击","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/1.血统与训练/5.通用类/工厂猎人/2.内脏暴击.md","filePath":"4.资源分区/1.血统与训练/5.通用类/工厂猎人/2.内脏暴击.md"}'),o={name:"4.资源分区/1.血统与训练/5.通用类/工厂猎人/2.内脏暴击.md"};function d(_,e,b,l,i,c){return t(),p("div",null,[...e[0]||(e[0]=[r("h1",{id:"_2-内脏暴击",tabindex:"-1"},[n("2.内脏暴击 "),r("a",{class:"header-anchor",href:"#_2-内脏暴击","aria-label":'Permalink to "2.内脏暴击"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：新世短歌037")])])],-1),s('<h1 id="内脏暴击" tabindex="-1">内脏暴击 <a class="header-anchor" href="#内脏暴击" aria-label="Permalink to &quot;内脏暴击&quot;">​</a></h1><p>该下属技能仅有你购买了工厂猎人训练，或者一手持【手枪/霰弹枪】并且一手持近战武器才可购买并使用。</p><p>内脏暴击（逐升技艺）<br> 猎人们特殊的攻击技能，通过火器或者重武器所进行的攻击使敌人产生硬直，从而给予自己机会对对方进行毁灭性的打击，其本质是猎人深入其伤口并且摧毁其内脏，是一种血腥但是绝对有效的攻击手段，但是特殊的，这种攻击的限制了猎人可以攻击的生物类型，是一个有一定限制的强大技能</p><p>D+500<br> 当对方在你的枪械的射程范围内，其攻击目标为你，并且满足以下条件时：<br> 1：对方在你近战攻击的触及范围内 <br> 2：对方必须为人型/动物 或者由这个类型组成的军团集群 <br> 3：体积差不高于3<br> 若满足条件，则你可以先使用反射动作透支下回合的一个标准动作（正常消耗下轮AP，并占用下轮动作转化上限，遵循透支规则，不具有打断性），使用自己的枪械进行一次不附带任何非常驻技艺的攻击（不会造成攻击附带的效果，也不会造成伤害），对方以反射豁免对抗此出目，若对方对抗成功，则你只会失去下回合标准动作而不会获得任何效果，若对方对抗失败，则陷入【僵直】状态，此时你需要进行一次不享有任何加值的自然骰，若本次自然骰出目为8/9/10，并且满足如上条件（此后不再复述），则触发‘内脏暴击’<br> 内脏暴击：你以近战武器对你触及距离内陷入【僵直】的一个目标施放内脏暴击，这视为使用近战武器进行的一次不附带任何招式的普通攻击，在攻击时获得5点破甲，若该破防属性结算目标防御后仍有剩余，则转化为攻击上的增强加值，至多转化5点。并且在攻击时额外获得2点附加成功。<br> 若本次自然骰判定失败，没能触发内脏暴击，但对方在你近战攻击的触及距离内，则你可以使用近战武器对目标进行一次不附带任何招式的普通攻击。<br> 特殊的，若对方进入【僵直】状态，并且不在你近战武器的触及距离之内，则你也可以改为使用枪械进行一次不附带任何招式的普通攻击，而无需只使用近战武器。</p><p>额外支付C+1000，该技艺效果将得到提升，取代D级效果。</p><p>现在只要对手当你持有的枪械的射程距离内，有敌人向你的队友攻击时，你也可以使用枪械尝试将敌人打入【僵直】，这视为一种打断性攻击，其他方面依旧遵循D等级内容中的限制。<br> 此外，你的内脏暴击效果获得提升。</p><p>当对方对抗失败陷入【僵直】状态时，现在你所投掷的自然骰成功数需求改为7/8/9/10，即可触发‘内脏暴击’<br> 【内脏暴击】：你以近战武器对你触及距离内陷入【僵直】的一个目标施放内脏暴击，这视为使用近战武器进行的一次不附带任何招式的普通攻击，你的这次攻击拥有【法破】【9加骰】，在攻击时获得5点破甲，若该破防属性结算目标防御后仍有剩余，则转化为攻击上的增强加值，至多转化5点。并且在攻击时额外获得2点附加成功。<br> 若本次自然骰判定失败，没能触发内脏暴击，但对方在你近战攻击的触及距离内，则你可以使用近战武器对目标进行一次不附带任何招式的普通攻击。<br> 特殊的，若对方进入【僵直】状态，并且不在你近战武器的触及距离之内，则你也可以改为使用枪械进行一次不附带任何招式的普通攻击，而无需只使用近战武器。</p><p>再额外支付B+2500，该技艺的效果将得到提升，取代C级效果。</p><p>保留C级可在队友被攻击时使用的条件，依旧具有【打断性】并在其他方面遵循D级内容中的限制。<br> 现在你在使用枪械在进行此技能的对抗以及攻击时，加骰等级提高一级处理，至多为【8加骰】。<br> 当对方对抗失败陷入【僵直】状态时，现在你所投掷的自然骰成功数需要改为6/7/8/9/10，即可触发‘内脏暴击’。</p><p>【内脏暴击】：你以近战武器对你触及距离内陷入【僵直】的一个目标施放内脏暴击，这视为使用近战武器进行的一次不附带任何招式的普通攻击，你的这次攻击拥有【法破】【9加骰】【湮灭】【狂怒5】，并且这次攻击视为【接触攻击】，在以近战进行攻击检定时，额外获得5点附加成功。<br> 若本次自然骰判定失败，没能触发内脏暴击，但对方在你近战攻击的触及距离内，则你可以使用近战武器对目标进行一次不附带任何招式的普通攻击。<br> 特殊的，若对方进入【僵直】状态，并且不在你近战武器的触及距离之内，则你也可以改为使用枪械进行一次不附带任何招式的普通攻击，而无需只使用近战武器。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',12)])])}const m=a(o,[["render",d]]);export{f as __pageData,m as default};
